const API_URL = 'http://localhost:5000/api/cultura';

export const getSitios = async () => {
    try {
        const res = await fetch(API_URL);
        return await res.json();
    } catch (error) {
        console.error("Error al obtener sitios:", error);
        return [];
    }
};

export const createSitio = async (nuevoSitio) => {
    try {
        const res = await fetch(API_URL, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(nuevoSitio)
        });
        return await res.json();
    } catch (error) {
        console.error("Error al crear sitio:", error);
    }
};

// ESTA ES LA FUNCIÓN PARA EL BOTÓN DE EDITAR
export const updateSitio = async (id, sitioActualizado) => {
    try {
        const res = await fetch(`${API_URL}/${id}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(sitioActualizado)
        });
        return await res.json();
    } catch (error) {
        console.error("Error al actualizar sitio:", error);
    }
};

export const deleteSitio = async (id) => {
    try {
        const res = await fetch(`${API_URL}/${id}`, { method: 'DELETE' });
        return await res.json();
    } catch (error) {
        console.error("Error al eliminar sitio:", error);
    }
};
